#include <stdio.h>

// JK Flip-Flop next state calculation
int jk_next_state(int J, int K, int Q) {
    // Characteristic equation: Q+ = JQ' + K'Q
    return (J && !Q) || (!K && Q);
}

int main() {
    int J, K, Q, Q_next;

    printf("J  K  Q | Q_next\n");
    printf("---------------\n");

    // Generate truth table
    for (Q = 0; Q <= 1; Q++) {
        for (J = 0; J <= 1; J++) {
            for (K = 0; K <= 1; K++) {
                Q_next = jk_next_state(J, K, Q);
                printf("%d  %d  %d |   %d\n", J, K, Q, Q_next);
            }
        }
    }
    return 0;
}

public class DFlipFlop {
    private boolean Q;      // Current state
    private boolean Q_bar;  // Complementary output
    private boolean D;      // Data input
    private boolean clock;  // Clock signal

    public DFlipFlop() {
        Q = false;
        Q_bar = true;
    }

    // Set data input
    public void setData(boolean D) {
        this.D = D;
    }

    // Clock edge detection (positive edge trigger)
    public void clockTick(boolean clockPulse) {
        if (clockPulse && !clock) {  // Rising edge detected
            // Sample input and update output
            Q = D;
            Q_bar = !D;
        }
        this.clock = clockPulse;
    }

    // Get current output
    public boolean getQ() {
        return Q;
    }

    // Main method for testing
    public static void main(String[] args) {
        DFlipFlop dff = new DFlipFlop();

        // Test sequence
        dff.setData(true);
        dff.clockTick(true);   // Rising edge - capture D=1
        System.out.println("Q after clock: " + dff.getQ());

        dff.setData(false);
        dff.clockTick(true);   // Rising edge - capture D=0
        System.out.println("Q after clock: " + dff.getQ());
    }
}
